<?php
use Livewire\Component; use Illuminate\Support\Facades\Auth;
new class extends Component { public string $email = ''; public string $password = ''; public function login(): void { $this->validate(['email' => 'required|email', 'password' => 'required']); if (! Auth::attempt(['email' => $this->email, 'password' => $this->password], true)) { $this->addError('email', 'Email atau password tidak tepat.'); return; } session()->regenerate(); $redirectRoute = auth()->user()?->role === 'admin' ? 'admin.dashboard' : 'dashboard'; $this->redirectRoute($redirectRoute); } }; ?>
<section class="login-panel"><p class="eyebrow">CMS</p><h1>Ruang Tumbuh</h1><p>Masuk untuk mengelola assessment.</p><form wire:submit="login"><label>Email<input wire:model="email" type="email"></label><label>Password<input wire:model="password" type="password"></label>@error('email')<p class="error">{{ $message }}</p>@enderror<button class="button" type="submit">Masuk</button></form><p class="hint">Demo: admin@ruangtumbuh.test / password</p></section>
